def build_story(title, subtitle, content_blocks):
    """
    Construye la lista de flowables para el documento.
    Prefijos especiales en content_blocks:
        '##'       -> H2
        '###'      -> H3
        '---'      -> Linea divisoria
        '>>>BREAK' -> Salto de pagina
        '-'        -> Bullet
    """
    story = []

    # Portada
    story.append(Spacer(1, 2 * cm))
    cover_title_style = ParagraphStyle(
        name="CoverTitle",
        fontSize=22,
        leading=28,
        alignment=TA_CENTER,
        fontName="Helvetica-Bold",
        textColor=colors.HexColor("#1A1A2E"),
    )
    story.append(Paragraph("Da&amp;Da Solutions", cover_title_style))
    story.append(Spacer(1, 0.4 * cm))
    story.append(HRFlowable(width="80%", thickness=2, color=colors.HexColor("#7C3AED")))
    story.append(Spacer(1, 0.6 * cm))

    doc_title_style = ParagraphStyle(
        name="DocTitle",
        fontSize=18,
        leading=24,
        alignment=TA_CENTER,
        fontName="Helvetica-Bold",
        textColor=colors.HexColor("#2D2D2D"),
    )
    story.append(Paragraph(title, doc_title_style))
    story.append(Spacer(1, 0.4 * cm))
    story.append(Paragraph(subtitle, styles['DaDaCenter']))
    story.append(Spacer(1, 1.5 * cm))
    story.append(HRFlowable(width="60%", thickness=1, color=colors.HexColor("#AAAAAA")))
    story.append(Spacer(1, 0.5 * cm))
    story.append(Paragraph("Documento Interno — Confidencial", styles['DaDaCenter']))
    story.append(Paragraph("Version 3.1  |  Anio 2026  |  Departamento de Ingenieria", styles['DaDaCenter']))
    story.append(PageBreak())

    # Contenido
    for block in content_blocks:
        s = block.strip()
        if s == ">>>BREAK":
            story.append(PageBreak())
        elif s == "---":
            story.append(Spacer(1, 6))
            story.append(HRFlowable(width="100%", thickness=0.5, color=colors.HexColor("#CCCCCC")))
            story.append(Spacer(1, 6))
        elif s.startswith("###"):
            story.append(Paragraph(s[3:].strip(), styles['DaDaH3']))
        elif s.startswith("##"):
            story.append(Paragraph(s[2:].strip(), styles['DaDaH2']))
        elif s.startswith("-"):
            story.append(Paragraph("&bull; " + s[1:].strip(), styles['DaDaBullet']))
        else:
            story.append(Paragraph(s, styles['DaDaJustify']))

    return story


def create_pdf(filename, title, subtitle, content_blocks):
    """Genera un archivo PDF con portada y contenido estructurado."""
    filepath = os.path.join("docs", filename)
    doc = SimpleDocTemplate(
        filepath,
        pagesize=A4,
        rightMargin=2.2 * cm,
        leftMargin=2.2 * cm,
        topMargin=2.2 * cm,
        bottomMargin=2 * cm,
    )
    doc.build(build_story(title, subtitle, content_blocks))
    print(f"  OK  Generado: {filename}")


